VALUES
  ('heelevel3-d0d1b9a2-moex-00345', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年1月1日將機器以融資租賃方式出租給乙公司，該機器原始成本$360,000，租 期5年，隱含利率10%，乙公司每年12月31日支付租金$91,690，租期屆滿時，機器歸還給 甲公司，估計租期屆滿時未保證殘值$20,000。X4年1月1日租期尚餘3年，二家公司同意 修改租約，租期不變，每期租金調升至$100,000，其餘條件不變。若修改租賃合約時已知剩餘 租賃期間之市場利率為8%，則甲公司X4年修改租約應認列租約修改(損)益為何？ 8% 10% 期數 普通年金現值 複利現值 普通年金現值 複利現值', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00346', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '2.57710 0.79383 2.48687 0.75131', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00347', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '3.99271 0.68058 3.79079 0.62092', '["$0", "$9,874", "$20,666", "$30,540"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00348', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於 X2 年初按公允價值$1,000,000 將一部機器出售給乙公司，該機器原始成本 $3,200,000，已提列累計折舊$2,000,000。甲公司旋即簽約租回，租期5年，每年1月1日支 付租金$208,000，租期屆滿時機器需歸還乙公司，估計租期屆滿時殘值為$20,000，全數由甲 公司保證，甲公司預期租期屆滿時機器之價值為$180,000。乙公司之租賃隱含利率為7%，且 為甲公司所知。若甲公司對該機器之移轉符合銷售之規定，則甲公司 X2 年初應認列處分機 器(損)益為何？（5期，7%，普通年金現值=4.10020，複利現值=0.71299；4期，7%，普通 年金現值=3.38721，複利現值=0.76290）', '["$(14,640)", "$(55,138)", "$(200,000)", "$73,200"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00349', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', 'X2年初甲公司之確定給付義務現值為$1,500,000，計畫資產公允價值為$1,200,000。X2年度 有關該確定給付計畫之相關資料如下：當期服務成本$300,000、計畫資產報酬$375,000、折現 率10%。甲公司於X2年期末提撥現金$750,000，並經評估得知該福利計畫之期末資產上限為 $300,000，則甲公司X2年應認列之其他綜合損益是多少？', '["$0", "其他綜合利益$180,000", "其他綜合利益$255,000", "其他綜合利益$345,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00350', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$1,000,000取得廠房，估計耐用年限10年，無殘值，會計上及報稅上均採直 線法折舊，但報稅上按5年計提折舊。X5年初，廠房重估價為公允價值$1,050,000，耐用年限及 殘值不變。甲公司將重估增值之其他權益分年隨折舊比例轉入保留盈餘，公司適用所得稅率為 20%。若該廠房預期透過繼續使用而回收，則甲公司X5年度有關遞延所得稅之敘述何者正確？', '["X5年底應認列遞延所得稅利益$5,000", "X5年底遞延所得稅負債餘額為$115,000", "X5年初重估價後遞延所得稅負債餘額為$90,000", "X5年初重估價後遞延所得稅負債餘額為$170,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00351', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年初流通在外普通股股數為200,000股，X2年初有認股權30,000單位流通在外， 每單位得按$40認購普通股1股，5月1日已認購18,000股，其餘12,000單位至X2年底仍 未執行。此外，X2年初公司有面額$1,000,000，票面利率4%之可轉換公司債，其中負債組成 部分之原始有效利率亦為4%，每$100,000面額可轉換成普通股10,000股，X2年9月1日有 $600,000可轉換公司債轉換成普通股60,000股，其餘債券至年底仍流通在外。甲公司普通股 X2 年 1 月 1 日至 4 月 30 日平均股價為$50，全年平均股價為$60。已知 X2 年稅後淨利為 $793,000，所得稅率為 20%，假設該可轉換公司債轉換為普通股對每股盈餘具稀釋效果，則 計算稀釋每股盈餘時分母應是多少？', '["307,600股", "316,667股", "317,200股", "318,000股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00352', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年1月1日以$1,200,000之價格發行面額$1,000,000，票面利率10%，5年期之 可轉換公司債，每年12月31日付息。該公司債可轉換成面額$10之普通股120,000股，發行 當時市場上相同條件之不附轉換權公司債之市場利率為8%。若甲公司於X5年1月1日由公 開市場以$1,295,000 之價格買回可轉換公司債，該日公司債組成部分之帳面價值為 $1,035,661，公允價值為$1,075,000，則買回公司債之會計處理何者正確？（8%，5期，普通 年金現值=3.99271，複利現值=0.68058；10%，5期，普通年金現值=3.79079，複利現值=0.62092）', '["借記保留盈餘$99,851", "借記債務清償損失$139,190", "貸記資本公積－認股權$120,149", "貸記資本公積－認股權$220,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00353', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年初以$1,100,000，另加$12,000交易成本，發行4年期之可買回公司債，面額 $1,000,000，票面利率5%，每年12月31日付息。甲公司得自X3年12月31日起，按面額 110另加應計利息買回該公司債，發行時該買回權資產之公允價值經評估為$50,000。公司認 為買回權與公司債兩者之經濟特性及風險並未緊密關聯，因此單獨認列嵌入式衍生工具。甲 公司對公司債採攤銷後成本處理，則X2年初發行此可買回債券時公司債之入帳金額為何？', '["$1,062,000", "$1,088,000", "$1,138,500", "$1,161,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00354', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年初以$20,000,000購入一棟商辦大樓，作為出租之用以賺取租金，估計耐用年 限40年，無殘值。該商辦大樓分類為投資性不動產，甲公司對投資性不動產採公允價值模式 衡量。X6 年初因商辦大樓電梯頻頻故障，決定將大樓電梯更換，換裝新電梯之成本共 $5,000,000。若舊電梯被重置時之公允價值為$800,000，X6年初及X6年底該商辦大樓公允價 值分別為$19,500,000及$24,000,000，則甲公司有關該投資性不動產相關會計處理對X6年度 損益之影響為何？', '["產生損失$300,000", "產生損失$500,000", "產生利益$300,000", "產生利益$500,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
